22	// UpdateOptions represents update command configuration
23	type UpdateOptions struct {
24		Check        bool
25		Force        bool
26		Reset        bool
27		Sync         bool
28		Strategy     string
29		Backup       bool
30		Interactive  bool
31		Abort        bool
32		DryRun       bool
33		Resource     string // selective update resource
34		DiscardLocal bool   // discard local changes when overwriting
35		Global       bool   // update global plugin tree instead of project tree
36	}
