120	// enumerateSkillUpdateTargets returns the destination paths that
121	// refreshShippedSkills would write to (files from the embedded ddx skill).
122	func enumerateSkillUpdateTargets(workingDir string) []string {
123		var result []string
124		_ = fs.WalkDir(skills.SkillFiles, "ddx", func(p string, d fs.DirEntry, _ error) error {
125			if d == nil || d.IsDir() {
126				return nil
127			}
128			rel, err := filepath.Rel("ddx", filepath.FromSlash(p))
129			if err != nil {
130				return nil
131			}
132			for _, base := range []string{
133				filepath.Join(workingDir, ".agents", "skills", "ddx"),
134				filepath.Join(workingDir, ".claude", "skills", "ddx"),
135			} {
136				result = append(result, filepath.Join(base, rel))
137			}
138			return nil
139		})
140		return result
141	}
