359	// refreshShippedSkills re-copies the embedded `ddx` skill into the project's
360	// skill directories and refreshes the AGENTS.md DDx block. Safe to call on
361	// every `ddx update` because skills.Install with Force=true handles the
362	// "existing files should be updated" case, and generateAgentsMD's
363	// marker-based merge is idempotent. Stale pre-consolidation skill dirs
364	// (ddx-bead, ddx-run, etc.) are swept by cleanupBootstrapSkills.
365	func refreshShippedSkills(workingDir string) {
366		bootstrapSkillNames := []string{"ddx"}
367		for _, dir := range []string{
368			filepath.Join(workingDir, ".agents", "skills"),
369			filepath.Join(workingDir, ".claude", "skills"),
370		} {
371			_ = os.MkdirAll(dir, 0755)
372			cleanupBootstrapSkills(dir, bootstrapSkillNames)
373		}
374		if err := skills.Install(skills.SkillFiles, workingDir, skills.Options{Force: true}); err != nil {
375			_, _ = fmt.Fprintf(os.Stderr, "Warning: skill install failed: %v\n", err)
376		}
377		generateAgentsMD(workingDir)
378	}
