419	// Output formatting function
420	func displayUpdateResult(cmd *cobra.Command, result *UpdateResult, opts *UpdateOptions) error {
421		green := color.New(color.FgGreen)
422		red := color.New(color.FgRed)
423	
424		out := cmd.OutOrStdout()
425		writer := out.(io.Writer)
426	
427		// Handle error cases
428		if !result.Success {
429			if len(result.Conflicts) > 0 {
430				return handleConflictOutput(out, result.Conflicts, opts)
431			}
432			_, _ = red.Fprintln(writer, "❌", result.Message)
433			return nil
434		}
435	
436		// Handle check mode
437		if opts.Check {
438			_, _ = fmt.Fprintln(writer, "Checking for updates...")
439			_, _ = fmt.Fprintln(writer, "Fetching latest changes from master repository...")
440			_, _ = fmt.Fprintln(writer, "Available updates:")
441			_, _ = fmt.Fprintln(writer, "Changes since last update:")
442			return nil
443		}
444	
445		// Handle dry-run mode
446		if opts.DryRun {
447			return displayDryRunResult(out, result, opts)
448		}
449	
450		// Display success message
451		_, _ = green.Fprintln(writer, "✅", result.Message)
452		_, _ = fmt.Fprintln(out)
453	
454		// Show updated files
455		if len(result.UpdatedFiles) > 0 {
456			_, _ = green.Fprintln(writer, "📦 Updated resources:")
457			for _, file := range result.UpdatedFiles {
458				_, _ = fmt.Fprintf(writer, "  • %s\n", file)
459			}
460			_, _ = fmt.Fprintln(out)
461		}
462	
463		// Show backup info
464		if result.BackupPath != "" {
465			_, _ = fmt.Fprintf(out, "💾 Backup created at: %s\n", result.BackupPath)
466			_, _ = fmt.Fprintln(out)
467		}
468	
469		return nil
470	}
