411	func prepareSymlinkTarget(target string, force bool) error {
412		if info, err := os.Lstat(target); err == nil {
413			if info.Mode()&os.ModeSymlink != 0 || force {
414				if err := os.RemoveAll(target); err != nil {
415					return fmt.Errorf("removing existing %s: %w", target, err)
416				}
417				return nil
418			}
419			return fmt.Errorf("%s already exists (use --force to replace)", target)
420		} else if !os.IsNotExist(err) {
421			return fmt.Errorf("checking existing %s: %w", target, err)
422		}
423		return nil
424	}
425	
426	// installLocal installs a plugin from a local directory as a developer overlay.
427	// When global is true, the plugin root is linked into the machine-wide global
428	// plugin tree and skills are linked into the home-level harness directories.
429	// When global is false, the plugin root and skills land in the project tree
430	// (in-tree mode: <project>/.ddx/plugins/<name>; convention mode: XDG project path).
431	// Local installs intentionally do not update the recorded installed state and
432	// do not auto-commit so the recorded plugin pin remains whatever the project
433	// already declares.
434	func (f *CommandFactory) installLocal(name, localPath string, force bool, global bool, out io.Writer) error {
435		// Resolve to absolute path.
436		absPath, err := filepath.Abs(localPath)
437		if err != nil {
438			return fmt.Errorf("resolving path %s: %w", localPath, err)
439		}
440		if _, err := os.Stat(absPath); os.IsNotExist(err) {
441			return fmt.Errorf("local path does not exist: %s", absPath)
442		}
443	
444		// Load package.yaml when present so local installs honor the manifest
445		// contract. If package.yaml is absent, use the plugin manifest rather than
446		// assuming a repository layout from the package name.
447		reg := registry.BuiltinRegistry()
448		fallbackPkg, _ := reg.Find(name)
449	
450		pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
451		if manifestMissing {
452			pluginPkg, ok, pluginErr := loadLocalPluginManifestPackage(absPath, name)
453			if pluginErr != nil {
454				return pluginErr
455			}
456			if ok {
457				pkg = pluginPkg
458			} else {
459				pkg = &registry.Package{
460					Name:        name,
461					Version:     "local",
462					Description: "local plugin package",
463					Type:        registry.PackageTypePlugin,
464					Source:      absPath,
465				}
466			}
467		}
468		if manifestErr == nil {
469			if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
470				return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
471			}
472		} else {
473			if os.IsNotExist(manifestErr) && manifestMissing {
474				// Already handled through package.yaml absence fallback above.
475			} else if len(manifestIssues) > 0 {
476				return fmt.Errorf("validating package manifest: %w", manifestErr)
477			} else {
478				return fmt.Errorf("loading package manifest: %w", manifestErr)
479			}
480		}
481	
482		if pkg == nil {
483			pkg = &registry.Package{
484				Name:        name,
485				Version:     "local",
486				Description: "local plugin package",
487				Type:        registry.PackageTypePlugin,
488				Source:      absPath,
489			}
490		}
491	
492		if pkg.Install.Root == nil {
493			pkg.Install.Root = &registry.InstallMapping{
494				Source: ".",
495				Target: fmt.Sprintf(".ddx/plugins/%s", pkg.Name),
496			}
497		}
498	
499		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
500			return fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
501		}
502	
503		projectRoot := f.WorkingDir
504		if projectRoot == "" {
505			projectRoot, _ = os.Getwd()
506		}
507		var oldFiles []string
508		if state, err := registry.LoadState(); err == nil {
509			if old := state.FindInstalled(pkg.Name); old != nil {
510				oldFiles = append([]string{}, old.Files...)
511				_, _ = markLocalInstallOverlay(projectRoot, pkg.Name, oldFiles)
512			}
513		}
514	
515		if issues := filterLocalInstallValidationIssues(absPath, registry.ValidatePackageStructure(absPath, pkg)); len(issues) > 0 {
516			return fmt.Errorf("validating package structure: %s", registry.JoinValidationIssues(issues))
517		}
518	
519		// Determine the actual plugin directory based on global vs project mode.
520		// Global: link into the machine-wide global tree.
521		// Project in-tree: link into <project>/.ddx/plugins/<name>.
522		// Project convention: link into the XDG convention root plugins/<name>.
523		// The FEAT-015 check above already validates that pkg.Install.Root.Target
524		// does not start with "~"; we now override the actual destination path.
525		var pluginDir string
526		if global {
527			pluginDir = filepath.Join(ddxroot.GlobalDir(), "plugins", name)
528		} else {
529			ddxRootDir := ddxroot.Path(context.Background(), f.WorkingDir)
530			pluginDir = filepath.Join(ddxRootDir, "plugins", name)
531		}
532	
533		if err := prepareSymlinkTarget(pluginDir, force); err != nil {
534			return err
535		}
536	
537		if err := os.MkdirAll(filepath.Dir(pluginDir), 0755); err != nil {
538			return fmt.Errorf("creating plugins dir: %w", err)
539		}
540	
541		if err := os.Symlink(absPath, pluginDir); err != nil {
542			return fmt.Errorf("linking plugin into %s: %w", pluginDir, err)
543		}
544	
545		fmt.Fprintf(out, "Linked %s -> %s\n", pluginDir, absPath)
546	
547		entry := registry.InstalledEntry{
548			Name:    pkg.Name,
549			Version: pkg.Version,
550			Type:    pkg.Type,
551			Source:  absPath,
552		}
553		// Record entry.Files as project-relative paths when the plugin lives inside
554		// the working directory (in-tree mode). Convention-root and global absolute
555		// paths are recorded as-is. This keeps removeStaleFilesFromInstall
556		// compatible with relative paths recorded by prior runs.
557		fileToRecord := pluginDir
558		if f.WorkingDir != "" {
559			if rel, relErr := filepath.Rel(f.WorkingDir, pluginDir); relErr == nil && !strings.HasPrefix(rel, "..") {
560				fileToRecord = rel
561			}
562		}
563		entry.Files = append(entry.Files, fileToRecord)
564	
565		// Install local skills as symlinks into each supported harness surface.
566		// For global installs, skills land in the home directory; for project
567		// installs, they land in the project directory.
568		if len(pkg.Install.Skills) > 0 {
569			var absProject string
570			if global {
571				absProject, _ = os.UserHomeDir()
572			} else {
573				absProject = f.WorkingDir
574				if absProject == "" {
575					absProject, _ = os.Getwd()
576				}
577			}
578			if !filepath.IsAbs(absProject) {
579				absProject, _ = filepath.Abs(absProject)
580			}
581			writtenSkills, err := installLocalSkillSymlinks(absPath, absProject, pkg.Install.Skills, force)
582			if err != nil {
583				return fmt.Errorf("installing skills: %w", err)
584			}
585			entry.Files = append(entry.Files, writtenSkills...)
586		}
587	
588		// Copy CLI script if defined (skip if target is a developer symlink).
589		if pkg.Install.Scripts != nil {
590			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
591			if li, lErr := os.Lstat(dst); lErr == nil && li.Mode()&os.ModeSymlink != 0 {
592				target, _ := os.Readlink(dst)
593				fmt.Fprintf(out, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
594				entry.Files = append(entry.Files, dst)
595			} else {
596				copied, err := registry.CopyScriptFromRoot(pluginDir, pkg.Install.Scripts)
597				if err != nil {
598					fmt.Fprintf(out, "Warning: script copy error: %v\n", err)
599				} else {
600					entry.Files = append(entry.Files, copied)
601				}
602			}
603		}
604	
605		// Set execute bits on installed plugin files.
606		for _, rel := range pkg.Install.Executable {
607			p := filepath.Join(pluginDir, filepath.FromSlash(rel))
608			if info, err := os.Stat(p); err == nil && !info.IsDir() {
609				_ = os.Chmod(p, info.Mode()|0111)
610			}
611		}
612	
613		entry.InstalledAt = time.Now()
614	
615		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
616		if removed > 0 {
617			fmt.Fprintf(out, "Removed %d stale file(s) from previous install\n", removed)
618		}
619	
620		// Git overlay hiding only applies to project-local installs (not global).
621		if !global {
622			if hidden, err := markLocalInstallOverlay(projectRoot, entry.Name, entry.Files); err != nil {
623				fmt.Fprintf(out, "Warning: local install is active but git overlay hiding failed: %v\n", err)
624			} else if hidden > 0 {
625				fmt.Fprintf(out, "Marked %d tracked local overlay file(s) skip-worktree\n", hidden)
626			}
627		}
628	
629		fmt.Fprintf(out, "Installed %s from local path %s — %d file(s); recorded plugin pin unchanged\n", entry.Name, absPath, len(entry.Files))
630		return nil
631	}
632	
633	func markLocalInstallOverlay(projectRoot, pluginName string, files []string) (int, error) {
634		if projectRoot == "" {
635			return 0, nil
636		}
637	
638		ctx := context.Background()
639		topOut, err := internalgit.Command(ctx, projectRoot, "rev-parse", "--show-toplevel").Output()
640		if err != nil {
641			return 0, nil
642		}
643		repoRoot := strings.TrimSpace(string(topOut))
644		if repoRoot == "" {
645			return 0, nil
646		}
647	
648		paths := localOverlayPaths(pluginName, files)
649		if len(paths) == 0 {
650			return 0, nil
651		}
652		if err := addLocalOverlayIgnores(repoRoot, paths); err != nil {
653			return 0, err
654		}
655	
656		args := append([]string{"ls-files", "-z", "--"}, paths...)
657		trackedOut, err := internalgit.Command(ctx, repoRoot, args...).Output()
658		if err != nil {
659			return 0, err
660		}
661		var tracked []string
662		for _, p := range strings.Split(string(trackedOut), "\x00") {
663			if p != "" {
664				tracked = append(tracked, p)
665			}
666		}
667		for start := 0; start < len(tracked); start += 100 {
668			end := start + 100
669			if end > len(tracked) {
670				end = len(tracked)
671			}
672			args := append([]string{"update-index", "--skip-worktree", "--"}, tracked[start:end]...)
673			if err := internalgit.Command(ctx, repoRoot, args...).Run(); err != nil {
674				return 0, err
675			}
676		}
677		return len(tracked), nil
678	}
