715	func installLocalSkillSymlinks(pluginRoot, projectRoot string, mappings []registry.InstallMapping, force bool) ([]string, error) {
716		sourceRoots, err := localSkillSourceRoots(pluginRoot, mappings)
717		if err != nil {
718			return nil, err
719		}
720		if len(sourceRoots) == 0 {
721			return nil, nil
722		}
723	
724		var written []string
725		seenSkills := map[string]bool{}
726		for _, sourceRoot := range sourceRoots {
727			entries, err := os.ReadDir(sourceRoot)
728			if err != nil {
729				return nil, err
730			}
731			for _, entry := range entries {
732				if !entry.IsDir() && entry.Type()&os.ModeSymlink == 0 {
733					continue
734				}
735				name := entry.Name()
736				if seenSkills[name] {
737					continue
738				}
739				src := filepath.Join(sourceRoot, name)
740				if _, err := os.Stat(filepath.Join(src, "SKILL.md")); err != nil {
741					return nil, fmt.Errorf("%s: missing SKILL.md: %w", src, err)
742				}
743				for _, surface := range []string{".agents/skills", ".claude/skills"} {
744					dst := filepath.Join(projectRoot, filepath.FromSlash(surface), name)
745					if err := prepareSymlinkTarget(dst, force); err != nil {
746						return nil, err
747					}
748					if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
749						return nil, fmt.Errorf("creating skills dir: %w", err)
750					}
751					target, err := filepath.Rel(filepath.Dir(dst), src)
752					if err != nil {
753						target = src
754					}
755					if err := os.Symlink(target, dst); err != nil {
756						return nil, fmt.Errorf("linking skill %s -> %s: %w", dst, target, err)
757					}
758					written = append(written, filepath.Join(filepath.FromSlash(surface), name))
759				}
760				seenSkills[name] = true
761			}
762		}
763		return written, nil
764	}
