802	func loadLocalPluginManifestPackage(root, expectedName string) (*registry.Package, bool, error) {
803		for _, rel := range []string{
804			filepath.Join(".codex-plugin", "plugin.json"),
805			filepath.Join(".claude-plugin", "plugin.json"),
806		} {
807			path := filepath.Join(root, rel)
808			data, err := os.ReadFile(path)
809			if os.IsNotExist(err) {
810				continue
811			}
812			if err != nil {
813				return nil, false, fmt.Errorf("loading plugin manifest %s: %w", path, err)
814			}
815			var manifest localPluginJSONManifest
816			if err := json.Unmarshal(data, &manifest); err != nil {
817				return nil, false, fmt.Errorf("loading plugin manifest %s: invalid JSON: %w", path, err)
818			}
819			name := strings.TrimSpace(manifest.Name)
820			if name == "" {
821				name = expectedName
822			}
823			if name != expectedName {
824				return nil, false, fmt.Errorf("local package name %q does not match plugin manifest name %q", expectedName, name)
825			}
826			sources, err := pluginManifestSkillSources(manifest.Skills)
827			if err != nil {
828				return nil, false, fmt.Errorf("loading plugin manifest %s: %w", path, err)
829			}
830			pkg := &registry.Package{
831				Name:        name,
832				Version:     defaultString(strings.TrimSpace(manifest.Version), "local"),
833				Description: defaultString(strings.TrimSpace(manifest.Description), "local plugin package"),
834				Type:        registry.PackageTypePlugin,
835				Source:      defaultString(strings.TrimSpace(manifest.Repository), root),
836				Install: registry.PackageInstall{
837					Root: &registry.InstallMapping{
838						Source: ".",
839						Target: fmt.Sprintf(".ddx/plugins/%s", name),
840					},
841				},
842			}
843			for _, source := range sources {
844				pkg.Install.Skills = append(pkg.Install.Skills, registry.InstallMapping{
845					Source: source,
846					Target: ".agents/skills/",
847				})
848			}
849			return pkg, true, nil
850		}
851		return nil, false, nil
852	}
