937	func filterLocalInstallValidationIssues(root string, issues []registry.ValidationIssue) []registry.ValidationIssue {
938		filtered := issues[:0]
939		roots := localInstallRootAliases(root)
940		ignoreCache := map[string]bool{}
941		for _, issue := range issues {
942			if rel, ok := localInstallIssueRel(roots, issue.Path); ok &&
943				(shouldSkipLocalInstallIssue(rel) || localInstallPathIsGitIgnored(root, rel, ignoreCache)) {
944				continue
945			}
946			filtered = append(filtered, issue)
947		}
948		return filtered
949	}
