975	func localInstallRootAliases(root string) []string {
976		seen := map[string]bool{}
977		var roots []string
978		add := func(path string) {
979			if strings.TrimSpace(path) == "" {
980				return
981			}
982			abs, err := filepath.Abs(path)
983			if err != nil {
984				abs = path
985			}
986			if !seen[abs] {
987				seen[abs] = true
988				roots = append(roots, abs)
989			}
990			if resolved, err := filepath.EvalSymlinks(abs); err == nil && resolved != "" && !seen[resolved] {
991				seen[resolved] = true
992				roots = append(roots, resolved)
993			}
994		}
995		add(root)
996		return roots
997	}
