999	func localInstallIssueRel(roots []string, path string) (string, bool) {
1000		for _, candidate := range localInstallPathAliases(path) {
1001			for _, root := range roots {
1002				rel, err := filepath.Rel(root, candidate)
1003				if err != nil || rel == "." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) || rel == ".." {
1004					continue
1005				}
1006				return filepath.ToSlash(rel), true
1007			}
1008		}
1009		return "", false
1010	}
