1157	func (f *CommandFactory) runVerify(cmd *cobra.Command, args []string) error {
1158		out := cmd.OutOrStdout()
1159	
1160		state, err := registry.LoadState()
1161		if err != nil {
1162			return fmt.Errorf("loading state: %w", err)
1163		}
1164	
1165		if len(state.Installed) == 0 {
1166			fmt.Fprintln(out, "No packages installed.")
1167			return nil
1168		}
1169	
1170		var totalIssues int
1171		for _, entry := range state.Installed {
1172			var issues []string
1173			for _, f := range entry.Files {
1174				expanded := registry.ExpandHome(f)
1175				info, err := os.Lstat(expanded)
1176				if os.IsNotExist(err) {
1177					issues = append(issues, fmt.Sprintf("  missing: %s", f))
1178					continue
1179				}
1180				if err != nil {
1181					issues = append(issues, fmt.Sprintf("  error: %s: %v", f, err))
1182					continue
1183				}
1184				// Check symlinks resolve.
1185				if info.Mode()&os.ModeSymlink != 0 {
1186					target, err := os.Readlink(expanded)
1187					if err != nil {
1188						issues = append(issues, fmt.Sprintf("  broken symlink: %s", f))
1189						continue
1190					}
1191					// Resolve relative symlinks against their parent directory.
1192					if !filepath.IsAbs(target) {
1193						target = filepath.Join(filepath.Dir(expanded), target)
1194					}
1195					if _, err := os.Stat(target); os.IsNotExist(err) {
1196						issues = append(issues, fmt.Sprintf("  broken symlink: %s -> %s", f, target))
1197					}
1198				}
1199			}
1200	
1201			if len(issues) == 0 {
1202				fmt.Fprintf(out, "%s %s: OK (%d files)\n", entry.Name, entry.Version, len(entry.Files))
1203			} else {
1204				fmt.Fprintf(out, "%s %s: %d issue(s)\n", entry.Name, entry.Version, len(issues))
1205				for _, issue := range issues {
1206					fmt.Fprintln(out, issue)
1207				}
1208				totalIssues += len(issues)
1209			}
1210		}
1211	
1212		if totalIssues > 0 {
1213			return fmt.Errorf("%d integrity issue(s) found — run 'ddx install <name> --force' to repair", totalIssues)
1214		}
1215		return nil
1216	}
