451	// legacySkillSymlinkDirs returns the relative names of project-local skill
452	// directories (e.g. ".agents/skills", ".claude/skills") whose DDx-managed
453	// ddx entry is still a symlink. That symlink indicates a pre-FEAT-015 DDx
454	// install; unrelated project-owned skill symlinks are ignored.
455	func legacySkillSymlinkDirs(workingDir string) []string {
456		if workingDir == "" {
457			return nil
458		}
459		var found []string
460		for _, rel := range []string{".agents/skills", ".claude/skills"} {
461			ddxSkillDir := filepath.Join(workingDir, rel, "ddx")
462			info, err := os.Lstat(ddxSkillDir)
463			if err != nil {
464				continue
465			}
466			if info.Mode()&os.ModeSymlink != 0 {
467				found = append(found, rel)
468			}
469		}
470		return found
471	}
