473	// runDoctorScoped runs only the checks relevant to the staged file paths,
474	// skipping global installation health checks unrelated to those files.
475	// It is the entry point when the ddx-validate pre-commit hook passes --paths.
476	//
477	// Scope rules:
478	//   - path == ".ddx.yml" (or ends with "/.ddx.yml") → config category: run config validation
479	//   - path under templates/, patterns/, prompts/ → resource category: validate resource files
480	//
481	// Any other paths (e.g. Go source files staged alongside config) are silently
482	// ignored — the scoped run only validates the DDx-relevant categories present
483	// in the staged set. Global checks (legacy symlinks, binary location, git repo
484	// health, etc.) are never run in scoped mode.
485	func (f *CommandFactory) runDoctorScoped(paths []string) error {
486		cats := categorizeStagedPaths(paths)
487		if cats["config"] {
488			if !checkConfiguration() {
489				return fmt.Errorf("DDx configuration invalid; run 'ddx doctor' for details")
490			}
491		}
492		// Resource category: syntax/schema checks for templates, patterns, prompts.
493		// Currently no additional validation beyond categorisation; the hook gate
494		// is satisfied by a clean parse (no-op until resource validators are added).
495		_ = cats["resource"]
496		return nil
497	}
