895				} else {
896					fmt.Println("✅ OK (developer symlink)")
897				}
898				continue
899			}
900	
901			// Regular file — check it's executable.
902			if li.Mode()&0111 != 0 {
903				fmt.Printf("✅ OK (%s)\n", dst)
904			} else {
905				fmt.Printf("⚠️  not executable (run: chmod +x %s)\n", dst)
