990	// checkGitRepoHealth detects git-repo corruption from prior ddx incidents:
991	//  1. core.bare=true on a repo that has a working tree (not actually bare)
992	//  2. Stray core.worktree that does not match the actual toplevel
993	//  3. Local core.hooksPath that prevents lefthook from managing hook sync
994	//  4. extensions.worktreeConfig not enabled (warning only)
995	//
996	// If fix is true, conditions (1), (2), and (3) are remediated with git config unset.
997	// (4) is always a warning — never auto-fixed, since enabling per-worktree config
998	// is a user-facing choice.
999	func checkGitRepoHealth(workingDir string, fix bool) []DiagnosticIssue {
1000		var issues []DiagnosticIssue
1001		ctx := context.Background()
1002	
1003		// Bail out quietly if this directory isn't a git repo at all. We can't rely
1004		// on `--is-inside-work-tree` here because the corruption we're looking for
1005		// (core.bare=true on a repo that has a working tree) causes git to report
1006		// "false" for that query. Instead, probe `--git-dir`, which succeeds on both
1007		// bare and non-bare repos.
1008		gitDirProbe := gitpkg.Command(ctx, workingDir, "rev-parse", "--git-dir")
1009		gdOut, err := gitDirProbe.Output()
1010		if err != nil {
1011			return nil
1012		}
1013		gitDirRaw := strings.TrimSpace(string(gdOut))
1014		if gitDirRaw == "" {
1015			return nil
1016		}
1017	
1018		// A "real" working tree on disk: either .git is a directory/file at
1019		// workingDir, or git reports a separate work-tree via --show-toplevel.
1020		// If neither holds, this is a genuinely bare repo → skip the checks.
1021		hasWorkTreeOnDisk := false
1022		if _, statErr := os.Stat(filepath.Join(workingDir, ".git")); statErr == nil {
1023			hasWorkTreeOnDisk = true
1024		}
1025		if !hasWorkTreeOnDisk {
1026			// Maybe we're inside a linked worktree where git treats us normally.
1027			inWT := gitpkg.Command(ctx, workingDir, "rev-parse", "--is-inside-work-tree")
1028			if b, err := inWT.Output(); err == nil && strings.TrimSpace(string(b)) == "true" {
1029				hasWorkTreeOnDisk = true
1030			}
1031		}
1032		if !hasWorkTreeOnDisk {
1033			return nil
1034		}
1035	
1036		gitConfigValue := func(key string) (string, bool) {
1037			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--get", key)
1038			b, err := c.Output()
1039			if err != nil {
1040				return "", false
1041			}
1042			return strings.TrimSpace(string(b)), true
1043		}
1044		gitConfigUnset := func(key string) error {
1045			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--unset", key)
1046			return c.Run()
1047		}
1048		gitConfigUnsetAll := func(key string) error {
1049			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--unset-all", key)
1050			return c.Run()
1051		}
1052	
1053		// (1) core.bare=true on a repo with a working tree → corruption.
1054		if val, ok := gitConfigValue("core.bare"); ok && val == "true" {
1055			desc := "core.bare=true is set on a repository that has a working tree (not actually bare)"
1056			rem := []string{"git config --unset core.bare"}
1057			if fix {
1058				if err := gitConfigUnset("core.bare"); err == nil {
1059					desc += " — removed"
1060				} else {
1061					desc += fmt.Sprintf(" — unset failed: %v", err)
1062				}
1063			}
1064			issues = append(issues, DiagnosticIssue{
1065				Type:        "git_core_bare_corruption",
1066				Description: desc,
1067				Remediation: rem,
1068			})
1069		}
1070	
1071		// (2) Stray core.worktree that doesn't match the directory we're running
1072		// against. Compare to workingDir directly — asking git for --show-toplevel
1073		// would just echo back core.worktree.
1074		if worktreeVal, ok := gitConfigValue("core.worktree"); ok && worktreeVal != "" {
1075			actual := workingDir
1076	
1077			cmpVal := worktreeVal
1078			if !filepath.IsAbs(cmpVal) {
1079				cmpVal = filepath.Clean(filepath.Join(gitDirRaw, worktreeVal))
1080			}
1081			resolvedCmp, _ := filepath.EvalSymlinks(cmpVal)
1082			if resolvedCmp == "" {
1083				resolvedCmp = cmpVal
1084			}
1085			resolvedActual, _ := filepath.EvalSymlinks(actual)
1086			if resolvedActual == "" {
1087				resolvedActual = actual
1088			}
1089	
1090			if actual != "" && resolvedCmp != resolvedActual {
1091				desc := fmt.Sprintf("core.worktree=%q does not match actual worktree %q", worktreeVal, actual)
1092				rem := []string{"git config --unset core.worktree"}
1093				if fix {
1094					if err := gitConfigUnset("core.worktree"); err == nil {
1095						desc += " — removed"
1096					} else {
1097						desc += fmt.Sprintf(" — unset failed: %v", err)
1098					}
1099				}
1100				issues = append(issues, DiagnosticIssue{
1101					Type:        "git_stray_core_worktree",
1102					Description: desc,
1103					Remediation: rem,
1104				})
1105			}
1106		}
1107	
1108		// (3) Local core.hooksPath interferes with lefthook's hook-path sync.
1109		if hooksPathVal, ok := gitConfigValue("core.hooksPath"); ok && hooksPathVal != "" {
1110			desc := fmt.Sprintf("core.hooksPath=%q is set locally; lefthook may skip hook-path sync and run stale hooks", hooksPathVal)
1111			rem := []string{
1112				"git config --unset-all --local core.hooksPath",
1113				"lefthook install --reset-hooks-path",
1114			}
1115			if fix {
1116				if err := gitConfigUnsetAll("core.hooksPath"); err == nil {
1117					desc += " — removed"
1118				} else {
1119					desc += fmt.Sprintf(" — unset failed: %v", err)
1120				}
1121			}
1122			issues = append(issues, DiagnosticIssue{
1123				Type:        "git_local_hooks_path",
1124				Description: desc,
1125				Remediation: rem,
1126			})
1127		}
1128	
1129		// (4) extensions.worktreeConfig not enabled → warning only.
1130		val, ok := gitConfigValue("extensions.worktreeConfig")
1131		if !ok || val != "true" {
1132			issues = append(issues, DiagnosticIssue{
1133				Type:        "git_worktree_config_disabled",
1134				Description: "extensions.worktreeConfig is not enabled; per-worktree config changes can corrupt the shared .git/config",
1135				Remediation: []string{
1136					"git config extensions.worktreeConfig true",
1137				},
1138			})
1139		}
1140	
1141		return issues
1142	}
1143	
1144	// packageJSONCheck holds the result of scanning one package.json location.
1145	type packageJSONCheck struct {
1146		Dir      string // relative path from project root (e.g. "website")
1147		HasPkg   bool   // package.json exists
1148		NeedsBun bool   // node_modules missing or stale vs bun.lock
1149		Reason   string // "missing" | "stale"
1150	}
1151	
1152	// knownPackageJSONDirs are the subdirectories (relative to workingDir) that
1153	// may contain a package.json. "" means the repo root itself.
1154	var knownPackageJSONDirs = []string{"", "website", "cli/internal/server/frontend"}
1155	
1156	// checkPackageJSONLocations scans the known package.json locations under
1157	// workingDir and returns a DiagnosticIssue for each location where
1158	// node_modules/ is absent or older than bun.lock.
1159	func checkPackageJSONLocations(workingDir string) []DiagnosticIssue {
1160		var issues []DiagnosticIssue
1161	
1162		for _, rel := range knownPackageJSONDirs {
1163			var dir string
1164			if rel == "" {
1165				dir = workingDir
1166			} else {
1167				dir = filepath.Join(workingDir, filepath.FromSlash(rel))
1168			}
1169	
1170			pkgPath := filepath.Join(dir, "package.json")
1171			if _, err := os.Stat(pkgPath); err != nil {
1172				continue // no package.json here
1173			}
1174	
1175			label := rel
1176			if label == "" {
1177				label = "(repo root)"
1178			}
1179	
1180			nmPath := filepath.Join(dir, "node_modules")
1181			nmInfo, nmErr := os.Stat(nmPath)
1182			if nmErr != nil {
1183				// node_modules missing entirely
1184				issues = append(issues, DiagnosticIssue{
1185					Type:        "node_modules_missing",
1186					Description: fmt.Sprintf("node_modules/ missing in %s", label),
1187					Remediation: []string{
1188						fmt.Sprintf("cd %s && bun install", dir),
1189					},
1190					SystemInfo: map[string]string{"package_json": pkgPath},
1191				})
1192				continue
1193			}
1194	
1195			// Check if bun.lock is newer than node_modules
1196			lockPath := filepath.Join(dir, "bun.lock")
1197			lockInfo, lockErr := os.Stat(lockPath)
1198			if lockErr == nil && lockInfo.ModTime().After(nmInfo.ModTime()) {
1199				issues = append(issues, DiagnosticIssue{
1200					Type:        "node_modules_stale",
1201					Description: fmt.Sprintf("node_modules/ in %s is older than bun.lock (run bun install)", label),
1202					Remediation: []string{
1203						fmt.Sprintf("cd %s && bun install", dir),
1204					},
1205					SystemInfo: map[string]string{"package_json": pkgPath},
1206				})
1207			}
1208		}
1209	
1210		return issues
1211	}
